// Input: all client rows from Master Sheet
const clients = $input.all();

// Get original webhook data
const webhook = $('📡 Webhook Zalo').first().json;

// Extract client_id from query string: ?client=AW001
const clientId = (webhook.query && webhook.query.client) ? webhook.query.client : '';

// Parse Zalo message payload
const body = webhook.body || {};
const msgText = (body.message && body.message.text) ? body.message.text.trim() : '';
const userId = (body.sender && body.sender.id) ? body.sender.id : '';

if (!clientId || !msgText || !userId) {
  return [{ json: { skip: true, reason: 'Missing client_id, message, or user_id' } }];
}

// Find matching client
const match = clients.find(c => c.json.client_id === clientId);
if (!match) {
  return [{ json: { skip: true, reason: 'Client not found: ' + clientId } }];
}

const client = match.json;

// Check if service is active
if (client.status !== 'active') {
  return [{
    json: {
      skip_ai: true,
      user_id: userId,
      access_token: client.zalo_access_token || '',
      reply_text: 'Dich vu hien dang tam dung. Vui long lien he chu doanh nghiep de biet them chi tiet.'
    }
  }];
}

// Build AI system prompt from client context
const businessContext = client.ai_context || 'Doanh nghiep wellness va spa chuyen nghiep';

// Detect if customer is greeting or asking about packages
const msgLower = msgText.toLowerCase();
const isGreeting = /^(xin chao|chao|hello|hi|hey|alo|cho hoi|cho minh hoi)/.test(msgLower);
const isAskingPackages = /(goi|package|bang gia|gia|dich vu gi|co nhung gi|gioi thieu|cac goi|muc gia|phi|bao nhieu)/.test(msgLower);

const packageInstruction = (isGreeting || isAskingPackages)
  ? 'Hay chao hoi than thien va gioi thieu ngan gon cac goi dich vu chinh cua ' + client.name + '.'
  : 'Chi tra loi dung vao cau hoi cua khach. KHONG gioi thieu lai cac goi dich vu tru khi khach hoi ve gia hoac dich vu.';

const systemPrompt = [
  'Ban la tro ly AI chuyen nghiep cho ' + client.name + '.',
  businessContext,
  packageInstruction,
  'Phong cach: ngan gon, than thien, chuyen nghiep. Dung tieng Viet.',
  'Neu khach muon dat lich: hoi Ten, So dien thoai, Ngay gio, Dich vu can.',
  'Neu khong ro y khach: hoi lai 1 cau ngan gon.'
].join(' ');

const apiBody = JSON.stringify({
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: msgText }
  ],
  max_tokens: 200,
  temperature: 0.7
});

return [{
  json: {
    skip_ai: false,
    user_id: userId,
    access_token: client.zalo_access_token || '',
    client_id: client.client_id,
    client_name: client.name,
    booking_sheet_id: client.booking_sheet_id || '',
    api_body: apiBody
  }
}];

const ai = $input.first().json;
const prev = $('🔍 Xác định khách hàng').first().json;

const replyText = (ai.choices && ai.choices[0] && ai.choices[0].message)
  ? ai.choices[0].message.content.trim()
  : 'Xin loi, hien tai he thong dang ban. Vui long thu lai sau.';

return [{
  json: {
    user_id: prev.user_id,
    access_token: prev.access_token,
    reply_text: replyText
  }
}];
